import React from 'react';
import Icon from '../../../components/AppIcon';
import Button from '../../../components/ui/Button';
import Image from '../../../components/AppImage';
import { getCautionModeLabel } from '../../../utils/cautionMode';

const ReservationCard = ({
  reservation,
  onAccept,
  onReject,
  onViewContract,
  onContactChat,
  contactCtaLabel = 'Contacter par chat',
  contactLoading = false
}) => {
  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date?.toLocaleDateString('fr-FR', {
      day: '2-digit',
      month: 'short',
      year: 'numeric'
    });
  };

  const formatDateTime = (dateString) => {
    const date = new Date(dateString);
    return date?.toLocaleDateString('fr-FR', {
      day: '2-digit',
      month: 'short',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const getCautionStatusConfig = (status, mode) => {
    const normalizedMode = String(mode || 'cb').trim().toLowerCase();
    const noneLabel = normalizedMode === 'assurance'
      ? 'Assurance'
      : normalizedMode === 'cheque'
        ? 'Cheque remis'
        : 'Aucune caution';

    const configs = {
      pending: { label: 'Enregistree', color: 'text-muted-foreground' },
      held: { label: 'Enregistree', color: 'text-muted-foreground' },
      authorized: { label: 'Enregistree', color: 'text-muted-foreground' },
      none: { label: noneLabel, color: 'text-primary' },
      released: { label: 'Remboursee', color: 'text-success' },
      captured: { label: 'Retenue', color: 'text-warning' }
    };
    return configs?.[status] || configs?.pending;
  };

  const getStatusConfig = (status) => {
    const configs = {
      pending: { label: 'En attente', color: 'bg-warning/10 text-warning', icon: 'Clock' },
      accepted: { label: 'Acceptee', color: 'bg-success/10 text-success', icon: 'CheckCircle' },
      rejected: { label: 'Refusee', color: 'bg-danger/10 text-danger', icon: 'XCircle' },
      ongoing: { label: 'En cours', color: 'bg-primary/10 text-primary', icon: 'Activity' },
      completed: { label: 'Terminee', color: 'bg-success/10 text-success', icon: 'CheckCircle' },
      cancelled: { label: 'Annulee', color: 'bg-muted/10 text-muted-foreground', icon: 'XCircle' }
    };
    return configs?.[status] || configs?.pending;
  };

  const getTimelineIcon = (type) => {
    const icons = {
      info: 'Info',
      success: 'CheckCircle',
      error: 'AlertCircle',
      pending: 'Clock'
    };
    return icons?.[type] || 'Circle';
  };

  const getTimelineColor = (type) => {
    const colors = {
      info: 'text-[#17a2b8] bg-[#17a2b8]/10 border-[#17a2b8]/20',
      success: 'text-success bg-success/10 border-success/20',
      error: 'text-error bg-error/10 border-error/20',
      pending: 'text-warning bg-warning/10 border-warning/20'
    };
    return colors?.[type] || 'text-muted-foreground bg-muted border-border';
  };

  const cautionConfig = getCautionStatusConfig(reservation?.cautionStatus, reservation?.cautionMode);
  const statusConfig = getStatusConfig(reservation?.status);
  const timeline = Array?.isArray(reservation?.timeline) ? reservation?.timeline : [];
  const cautionModeLabel = getCautionModeLabel(reservation?.cautionMode);

  const requestDate = new Date(reservation?.requestDate);
  const now = new Date();
  const hoursSinceRequest = (now - requestDate) / (1000 * 60 * 60);
  const willAutoCancel = reservation?.status === 'pending' && hoursSinceRequest < 48;
  const hoursRemaining = willAutoCancel ? Math.max(0, 48 - hoursSinceRequest) : 0;

  return (
    <div className="bg-white rounded-lg border border-border p-6 hover:shadow-elevation-2 transition-shadow">
      <div className="flex flex-col lg:flex-row gap-4">
        <div className="w-full lg:w-48 h-48 flex-shrink-0">
          <Image
            src={reservation?.equipmentImage}
            alt={reservation?.equipmentImageAlt}
            className="w-full h-full object-cover rounded-lg"
          />
        </div>

        <div className="flex-1 space-y-4">
          <div className="flex flex-col md:flex-row md:items-start md:justify-between gap-3">
            <div>
              <h3 className="text-xl font-bold text-foreground mb-1">{reservation?.equipmentTitle}</h3>
              <p className="text-sm text-muted-foreground">Reference: {reservation?.id}</p>
            </div>
            <span className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium ${statusConfig?.color} whitespace-nowrap`}>
              <Icon name={statusConfig?.icon} size={14} />
              {statusConfig?.label}
            </span>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-full overflow-hidden flex-shrink-0">
                <img
                  src={reservation?.renterAvatar}
                  alt={`Avatar de ${reservation?.renterPseudo}`}
                  className="w-full h-full object-cover"
                />
              </div>
              <div>
                <p className="text-xs text-muted-foreground">Locataire</p>
                <p className="font-medium text-foreground">{reservation?.renterPseudo}</p>
              </div>
            </div>

            <div>
              <p className="text-xs text-muted-foreground mb-1">Periode de location</p>
              <p className="font-medium text-foreground">
                {formatDate(reservation?.startDate)} - {formatDate(reservation?.endDate)}
              </p>
            </div>

            <div>
              <p className="text-xs text-muted-foreground mb-1">Montant total</p>
              <p className="font-semibold text-foreground text-lg">{reservation?.totalAmount?.toFixed(2)} EUR</p>
            </div>

            <div>
              <p className="text-xs text-muted-foreground mb-1">Caution</p>
              <p className="font-medium text-foreground">
                {reservation?.cautionAmount?.toFixed(2)} EUR
                <span className={`ml-2 text-xs ${cautionConfig?.color}`}>({cautionConfig?.label} - {cautionModeLabel})</span>
              </p>
            </div>
          </div>

          {willAutoCancel && (
            <div className="bg-warning/10 border border-warning/20 rounded-lg p-3">
              <div className="flex gap-2">
                <Icon name="AlertTriangle" size={16} className="text-warning flex-shrink-0 mt-0.5" />
                <p className="text-xs text-foreground">
                  Cette demande sera automatiquement annulee dans <strong>{Math.floor(hoursRemaining)}h</strong> si vous ne repondez pas.
                </p>
              </div>
            </div>
          )}

          {timeline?.length > 0 && (
            <div className="bg-surface rounded-lg border border-border p-4">
              <h4 className="text-sm font-semibold text-foreground mb-3">Historique de la reservation</h4>
              <div className="overflow-x-auto pb-1">
                <div className="relative min-w-max px-1">
                  {timeline?.length > 1 && (
                    <div className="absolute left-6 right-6 top-5 h-0.5 bg-border" />
                  )}

                  <div className="relative flex items-start gap-4">
                    {timeline?.map((event, index) => (
                      <div key={`${reservation?.id}-timeline-${index}`} className="w-[220px] flex-shrink-0">
                        <div className={`w-10 h-10 rounded-full border flex items-center justify-center ${getTimelineColor(event?.type)} relative z-10`}>
                          <Icon name={getTimelineIcon(event?.type)} size={18} />
                        </div>
                        <div className="mt-3">
                          <p className="text-sm font-medium text-foreground leading-snug">{event?.event}</p>
                          <p className="text-xs text-muted-foreground mt-1">{formatDateTime(event?.date)}</p>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            </div>
          )}

          <div className="flex items-center gap-3 flex-wrap">
            {reservation?.status === 'ongoing' && (
              <Button
                variant="default"
                iconName="MessageCircle"
                onClick={() => onContactChat?.(reservation)}
                loading={contactLoading}
                disabled={contactLoading}
                className="bg-[#17a2b8] hover:bg-[#138496] text-white font-semibold shadow-sm ring-2 ring-[#17a2b8]/20"
              >
                {contactCtaLabel}
              </Button>
            )}

            {reservation?.status === 'pending' && (
              <>
                <Button
                  variant="success"
                  size="sm"
                  iconName="CheckCircle"
                  onClick={() => onAccept?.(reservation)}
                >
                  Accepter
                </Button>
                <Button
                  variant="danger"
                  size="sm"
                  iconName="XCircle"
                  onClick={() => onReject?.(reservation)}
                >
                  Refuser
                </Button>
              </>
            )}

            {reservation?.contractUrl && (
              <Button
                variant="outline"
                size="sm"
                iconName="FileText"
                onClick={() => onViewContract?.(reservation)}
              >
                Voir le contrat
              </Button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default ReservationCard;
