import React, { useEffect, useState } from 'react';
import Header from '../../components/navigation/Header';
import { useNavigate } from 'react-router-dom';
import Footer from '../../components/Footer';
import Icon from '../../components/AppIcon';
import Select from '../../components/ui/Select';
import ReservationCard from './components/ReservationCard';
import AcceptRejectModal from './components/AcceptRejectModal';
import ContractPreviewModal from './components/ContractPreviewModal';
import { useAuth } from '../../contexts/AuthContext';
import reservationService from '../../services/reservationService';
import storageService from '../../services/storageService';
import messageService from '../../services/messageService';

const FALLBACK_IMAGE = '/assets/images/no_image.png';

const normalizeStatus = (status) => {
  switch (status) {
    case 'pending':
      return 'pending';
    case 'accepted':
    case 'paid':
    case 'active':
      return 'ongoing';
    case 'completed':
      return 'completed';
    case 'refused':
    case 'rejected':
    case 'cancelled':
      return 'cancelled';
    default:
      return 'pending';
  }
};

const resolvePhotoCandidate = (candidate) => {
  if (!candidate) return null;

  if (Array.isArray(candidate)) {
    for (const item of candidate) {
      const resolved = resolvePhotoCandidate(item);
      if (resolved) return resolved;
    }
    return null;
  }

  if (typeof candidate === 'object') {
    return resolvePhotoCandidate(
      candidate?.url
      || candidate?.src
      || candidate?.file_url
      || candidate?.path
      || candidate?.image_url
      || candidate?.photo_url
    );
  }

  if (typeof candidate !== 'string') return null;
  const rawValue = candidate?.trim();
  if (!rawValue) return null;

  if (rawValue?.startsWith('[') || rawValue?.startsWith('{')) {
    try {
      return resolvePhotoCandidate(JSON.parse(rawValue));
    } catch (_error) {
      return null;
    }
  }

  return storageService?.getAnnoncePhotoUrl(rawValue) || rawValue;
};

const getPhotoUrl = (annonce) => {
  const candidates = [
    annonce?.photos,
    annonce?.images,
    annonce?.image,
    annonce?.image_url,
    annonce?.photo_url
  ];

  for (const candidate of candidates) {
    const resolved = resolvePhotoCandidate(candidate);
    if (resolved) return resolved;
  }

  return FALLBACK_IMAGE;
};

const pushTimelineEvent = (timeline, dateValue, event, type) => {
  if (!dateValue) return;
  const date = new Date(dateValue);
  if (Number.isNaN(date?.getTime())) return;
  timeline?.push({ date: date?.toISOString(), event, type });
};

const buildTimeline = (reservation) => {
  const timeline = [];

  pushTimelineEvent(timeline, reservation?.created_at, 'Demande de reservation creee', 'info');
  pushTimelineEvent(timeline, reservation?.owner_confirmed_at, 'Demande acceptee par le proprietaire', 'success');
  pushTimelineEvent(timeline, reservation?.paid_at || reservation?.tenant_payment_paid_at, 'Paiement effectue', 'success');
  pushTimelineEvent(timeline, reservation?.start_date, 'Debut de location prevu', 'pending');
  pushTimelineEvent(timeline, reservation?.end_date, 'Fin de location prevue', 'pending');
  pushTimelineEvent(timeline, reservation?.completed_at, 'Location terminee', 'success');
  pushTimelineEvent(timeline, reservation?.cancelled_at, 'Reservation annulee', 'error');

  if (timeline?.length === 0) {
    pushTimelineEvent(timeline, reservation?.updated_at, 'Mise a jour de la reservation', 'info');
  }

  return timeline?.sort((a, b) => new Date(a?.date) - new Date(b?.date));
};

const mapReservationToCard = (reservation) => {
  const totalAmount = Number.parseFloat(reservation?.total_price ?? reservation?.totalAmount ?? 0);
  const cautionAmount = Number.parseFloat(
    reservation?.caution_amount ?? reservation?.deposit_amount ?? reservation?.annonce?.caution ?? 0
  );

  return {
    id: reservation?.id,
    annonceId: reservation?.annonce_id,
    ownerId: reservation?.owner_id,
    renterId: reservation?.renter_id,
    equipmentTitle: reservation?.annonce?.titre || 'Annonce',
    equipmentImage: getPhotoUrl(reservation?.annonce),
    equipmentImageAlt: reservation?.annonce?.titre || 'Materiel',
    renterPseudo: reservation?.renter?.pseudo || 'Locataire',
    renterAvatar: reservation?.renter?.avatar_url || FALLBACK_IMAGE,
    startDate: reservation?.start_date,
    endDate: reservation?.end_date,
    status: normalizeStatus(reservation?.status),
    totalAmount: Number.isFinite(totalAmount) ? totalAmount : 0,
    cautionAmount: Number.isFinite(cautionAmount) ? cautionAmount : 0,
    cautionStatus: reservation?.deposit_status || reservation?.caution_status || 'pending',
    cautionMode: reservation?.caution_mode || reservation?.mode_caution || 'cb',
    requestDate: reservation?.created_at || reservation?.updated_at || reservation?.start_date,
    timeline: buildTimeline(reservation),
    contractUrl: reservation?.contract_url || null,
    rawStatus: reservation?.status
  };
};

const ReservationManagementDashboard = () => {
  const navigate = useNavigate();
  const { user, loading: authLoading } = useAuth();
  const [statusFilter, setStatusFilter] = useState('all');
  const [selectedReservation, setSelectedReservation] = useState(null);
  const [showAcceptRejectModal, setShowAcceptRejectModal] = useState(false);
  const [showContractModal, setShowContractModal] = useState(false);
  const [actionType, setActionType] = useState(null);
  const [reservations, setReservations] = useState([]);
  const [loading, setLoading] = useState(true);
  const [loadError, setLoadError] = useState(null);
  const [startingChatReservationId, setStartingChatReservationId] = useState(null);

  const loadReservations = async () => {
    if (!user?.id) {
      setReservations([]);
      setLoading(false);
      return;
    }

    setLoading(true);
    setLoadError(null);

    try {
      const { data, error } = await reservationService?.getOwnerReservations(user?.id);
      if (error) throw error;

      setReservations((data || [])?.map(mapReservationToCard));
    } catch (error) {
      console.error('Erreur lors du chargement des reservations:', error);
      setReservations([]);
      setLoadError('Impossible de charger les reservations pour le moment.');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (authLoading) return;
    loadReservations();
  }, [user?.id, authLoading]);

  const filteredReservations = statusFilter === 'all'
    ? reservations
    : reservations?.filter((reservation) => reservation?.status === statusFilter);

  const statusOptions = [
    { value: 'all', label: 'Toutes' },
    { value: 'pending', label: 'En attente' },
    { value: 'ongoing', label: 'En cours' },
    { value: 'completed', label: 'Terminees' },
    { value: 'cancelled', label: 'Annulees' }
  ];

  const stats = [
    {
      label: 'En attente',
      value: reservations?.filter((reservation) => reservation?.status === 'pending')?.length,
      icon: 'Clock',
      color: 'text-warning bg-warning/10'
    },
    {
      label: 'En cours',
      value: reservations?.filter((reservation) => reservation?.status === 'ongoing')?.length,
      icon: 'PlayCircle',
      color: 'text-[#17a2b8] bg-[#17a2b8]/10'
    },
    {
      label: 'Terminees',
      value: reservations?.filter((reservation) => reservation?.status === 'completed')?.length,
      icon: 'CheckCircle',
      color: 'text-success bg-success/10'
    }
  ];

  const handleViewContract = (reservation) => {
    setSelectedReservation(reservation);
    setShowContractModal(true);
  };

  const handleAccept = (reservation) => {
    setSelectedReservation(reservation);
    setActionType('accept');
    setShowAcceptRejectModal(true);
  };

  const handleReject = (reservation) => {
    setSelectedReservation(reservation);
    setActionType('reject');
    setShowAcceptRejectModal(true);
  };

  const handleActionSubmit = async (message) => {
    if (!selectedReservation?.id) return;

    try {
      let result;

      if (actionType === 'accept') {
        result = await reservationService?.acceptReservation(selectedReservation?.id);
      } else if (actionType === 'reject') {
        result = await reservationService?.refuseReservation(selectedReservation?.id, message?.trim());
      }

      if (result?.error) {
        throw result?.error;
      }

      setShowAcceptRejectModal(false);
      setSelectedReservation(null);
      setActionType(null);
      await loadReservations();
    } catch (error) {
      console.error('Erreur lors de la mise a jour de la reservation:', error);
      alert('Erreur lors de la mise a jour de la reservation');
    }
  };

  const closeAcceptRejectModal = () => {
    setShowAcceptRejectModal(false);
    setActionType(null);
  };

  const closeContractModal = () => {
    setShowContractModal(false);
    setSelectedReservation(null);
  };

  const handleContactChat = async (reservation) => {
    const currentUserId = String(user?.id || '');
    const ownerId = String(reservation?.ownerId || '');
    const renterId = String(reservation?.renterId || '');
    const annonceId = reservation?.annonceId;
    const otherParticipantId = currentUserId === ownerId ? renterId : ownerId;

    if (!currentUserId || !otherParticipantId || !annonceId) {
      window.alert('Impossible d ouvrir le chat pour cette reservation.');
      return;
    }

    try {
      setStartingChatReservationId(reservation?.id || null);

      const { data, error } = await messageService?.getOrCreateConversation(annonceId, [
        currentUserId,
        otherParticipantId
      ]);

      if (error) throw error;
      if (!data?.id) throw new Error('Conversation introuvable.');

      navigate(`/tableau-bord-utilisateur?tab=messages&conversation=${encodeURIComponent(data?.id)}`);
    } catch (error) {
      console.error('Erreur ouverture chat reservation:', error);
      window.alert(error?.message || 'Impossible d ouvrir le chat pour le moment.');
    } finally {
      setStartingChatReservationId(null);
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-background">
      <Header />
      <main className="flex-1 container mx-auto px-4 py-8">
        <div className="flex items-center gap-2 text-sm text-muted-foreground mb-6">
          <a href="/tableau-bord-utilisateur" className="hover:text-[#17a2b8] transition-colors">Tableau de bord</a>
          <Icon name="ChevronRight" size={14} />
          <span className="text-foreground">Mes reservations</span>
        </div>

        <div className="mb-6">
          <h1 className="text-2xl md:text-3xl font-bold text-foreground mb-2">Gestion des reservations</h1>
          <p className="text-muted-foreground">Gerez vos demandes de reservation et suivez leur statut</p>
        </div>

        {loadError && (
          <div className="bg-warning/10 border border-warning/20 rounded-lg p-4 mb-6 text-sm text-foreground">
            {loadError}
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
          {stats?.map((stat) => (
            <div key={stat?.label} className="bg-white rounded-lg shadow-elevation-1 p-4 md:p-6">
              <div className="flex items-start justify-between">
                <div className="flex-1">
                  <p className="text-sm text-muted-foreground mb-1">{stat?.label}</p>
                  <p className="text-3xl font-bold text-foreground">{stat?.value}</p>
                </div>
                <div className={`p-3 rounded-lg ${stat?.color}`}>
                  <Icon name={stat?.icon} size={24} />
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="bg-white rounded-lg shadow-elevation-1 p-4 mb-6">
          <Select
            options={statusOptions}
            value={statusFilter}
            onChange={setStatusFilter}
            placeholder="Filtrer par statut" />
        </div>

        <div className="space-y-4">
          {loading ? (
            <div className="bg-white rounded-lg shadow-elevation-1 p-12 text-center">
              <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-primary mx-auto mb-3"></div>
              <p className="text-muted-foreground">Chargement des reservations...</p>
            </div>
          ) : filteredReservations?.length === 0 ? (
            <div className="bg-white rounded-lg shadow-elevation-1 p-12 text-center">
              <Icon name="Calendar" size={48} className="mx-auto text-muted-foreground mb-3" />
              <p className="text-muted-foreground">Aucune reservation trouvee</p>
            </div>
          ) : (
            filteredReservations?.map((reservation) => {
              const currentUserId = String(user?.id || '');
              const isOwner = currentUserId && currentUserId === String(reservation?.ownerId || '');
              const contactCtaLabel = isOwner ? 'Contacter le locataire' : 'Contacter le proprietaire';

              return (
                <ReservationCard
                  key={reservation?.id}
                  reservation={reservation}
                  onAccept={handleAccept}
                  onReject={handleReject}
                  onViewContract={handleViewContract}
                  onContactChat={handleContactChat}
                  contactCtaLabel={contactCtaLabel}
                  contactLoading={String(startingChatReservationId || '') === String(reservation?.id || '')} />
              );
            })
          )}
        </div>

        {showContractModal && selectedReservation?.contractUrl && (
          <ContractPreviewModal
            reservation={selectedReservation}
            contractUrl={selectedReservation?.contractUrl}
            onClose={closeContractModal} />
        )}
      </main>
      <Footer />

      {showAcceptRejectModal && selectedReservation && (
        <AcceptRejectModal
          reservation={selectedReservation}
          actionType={actionType}
          onClose={closeAcceptRejectModal}
          onSubmit={handleActionSubmit} />
      )}
    </div>
  );
};

export default ReservationManagementDashboard;
